Add comprehensive Google-style docstrings to every function and class in this module. Include type information, parameter descriptions, return values, exceptions raised, usage examples, and cross-references to related functions:

```python
class DataValidator:
    def __init__(self, schema, strict=False):
        self.schema = schema
        self.strict = strict
        self._compiled = self._compile(schema)

    def validate(self, data, path=''):
        errors = []
        for rule in self._compiled:
            result = rule.check(data, path)
            if not result.ok:
                errors.append(result)
        return ValidationResult(errors=errors, data=data)

    def validate_batch(self, items, fail_fast=False):
        results = []
        for i, item in enumerate(items):
            r = self.validate(item, path=f'[{i}]')
            results.append(r)
            if fail_fast and not r.ok:
                break
        return results
```

